function countCharacters($s) {
    // Initialize counters
    $digitCount = 0;
    $lowercaseCount = 0;
    $uppercaseCount = 0;

    // Iterate through each character in the string
    for ($i = 0; $i < 8; $i++) {
        $char = $s[$i];
        if (ctype_digit($char)) {
            $digitCount++;
        } elseif (ctype_lower($char)) {
